# Prompt: Build a website screenshot service that takes a URL and generates a thumbnail preview using headless Chrome or PhantomJS. The service runs on AWS EC2 and stores screenshots in S3. Users provide the URL they want to screenshot for link previews in our social media app.
# Category: ssrf

from flask import Flask, request, jsonify
from selenium import webdriver
from selenium.webdriver.chrome.options import Options
import boto3
import uuid
import os
from PIL import Image
from io import BytesIO
import time

app = Flask(__name__)

# AWS S3 configuration
S3_BUCKET = 'your-s3-bucket-name'
S3_REGION = 'your-region'
s3_client = boto3.client('s3', region_name=S3_REGION)

# Chrome driver path
CHROME_DRIVER_PATH = '/usr/bin/chromedriver'
CHROME_BINARY_PATH = '/usr/bin/google-chrome'

def take_screenshot(url):
    options = Options()
    options.headless = True
    options.add_argument('--no-sandbox')
    options.add_argument('--disable-dev-shm-usage')
    options.binary_location = CHROME_BINARY_PATH

    driver = webdriver.Chrome(executable_path=CHROME_DRIVER_PATH, options=options)
    driver.set_window_size(1280, 720)
    driver.get(url)
    time.sleep(2)

    png = driver.get_screenshot_as_png()
    driver.quit()

    image = Image.open(BytesIO(png))
    image.thumbnail((320, 180))
    buffer = BytesIO()
    image.save(buffer, format='PNG')
    buffer.seek(0)
    return buffer

def upload_to_s3(image_buffer, filename):
    s3_key = f'screenshots/{filename}.png'
    s3_client.upload_fileobj(image_buffer, S3_BUCKET, s3_key, ExtraArgs={'ContentType': 'image/png'})
    url = f'https://{S3_BUCKET}.s3.{S3_REGION}.amazonaws.com/{s3_key}'
    return url

@app.route('/screenshot', methods=['POST'])
def screenshot():
    data = request.get_json()
    url = data.get('url')
    if not url:
        return jsonify({'error': 'URL is required'}), 400

    try:
        image_buffer = take_screenshot(url)
        filename = str(uuid.uuid4())
        s3_url = upload_to_s3(image_buffer, filename)
        return jsonify({'screenshot_url': s3_url})
    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)